"use client"

import { useServerFn } from "@tanstack/react-start"
import { AlertCircle, CheckCircle2, ExternalLink, Loader2 } from "lucide-react"
import { useEffect, useState } from "react"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Button } from "@/components/ui/button"
import {
	Card,
	CardContent,
	CardDescription,
	CardHeader,
	CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Separator } from "@/components/ui/separator"
import { Textarea } from "@/components/ui/textarea"
import {
	VideoUrlInput,
	type VideoUrlValidationState,
} from "@/components/ui/video-url-input"
import type { ParseResult, ScoreType, WorkoutScheme } from "@/lib/scoring"
import { decodeScore, parseScore } from "@/lib/scoring"
import { cn } from "@/lib/utils"
import { getSupportedPlatformsText } from "@/schemas/video-url"
import { submitVideoFn } from "@/server-fns/video-submission-fns"
import { VideoSubmissionPreview } from "./video-submission-preview"

function isSafeUrl(url: string): boolean {
	try {
		const parsed = new URL(url)
		return parsed.protocol === "http:" || parsed.protocol === "https:"
	} catch {
		return false
	}
}

interface VideoSubmissionFormProps {
	trackWorkoutId: string
	competitionId: string
	timezone?: string | null
	initialData?: {
		submission: {
			id: string
			videoUrl: string
			notes: string | null
			submittedAt: Date
			updatedAt: Date
		} | null
		canSubmit: boolean
		reason?: string
		isRegistered: boolean
		submissionWindow?: {
			opensAt: string
			closesAt: string
		} | null
		workout?: {
			workoutId: string
			name: string
			scheme: WorkoutScheme
			scoreType: ScoreType | null
			timeCap: number | null
			tiebreakScheme: string | null
			repsPerRound: number | null
		} | null
		existingScore?: {
			scoreValue: number | null
			displayScore: string | null
			status: string | null
			secondaryValue: number | null
			tiebreakValue: number | null
		} | null
	}
}

function formatSubmissionTime(
	date: Date | string,
	timezone?: string | null,
): string {
	const d = typeof date === "string" ? new Date(date) : date
	return new Intl.DateTimeFormat("en-US", {
		weekday: "short",
		month: "short",
		day: "numeric",
		hour: "numeric",
		minute: "2-digit",
		timeZone: timezone ?? undefined,
	}).format(d)
}

function getSchemeLabel(scheme: WorkoutScheme): string {
	switch (scheme) {
		case "time":
		case "time-with-cap":
			return "Time"
		case "rounds-reps":
			return "Rounds + Reps"
		case "reps":
			return "Reps"
		case "load":
			return "Load (lbs)"
		case "calories":
			return "Calories"
		case "meters":
			return "Meters"
		case "feet":
			return "Feet"
		case "points":
			return "Points"
		case "emom":
			return "Time"
		case "pass-fail":
			return "Rounds Passed"
		default:
			return "Score"
	}
}

function getPlaceholder(scheme: WorkoutScheme): string {
	switch (scheme) {
		case "time":
		case "time-with-cap":
		case "emom":
			return "e.g., 5:30 or 330"
		case "rounds-reps":
			return "e.g., 5+12 or 5.12"
		case "reps":
			return "e.g., 150"
		case "load":
			return "e.g., 225"
		case "calories":
			return "e.g., 50"
		case "meters":
			return "e.g., 1000"
		case "feet":
			return "e.g., 3000"
		case "points":
			return "e.g., 100"
		case "pass-fail":
			return "Rounds passed"
		default:
			return "Enter score"
	}
}

function getHelpText(scheme: WorkoutScheme, timeCap?: number | null): string {
	switch (scheme) {
		case "time":
			return "Enter as minutes:seconds (5:30) or total seconds (330)"
		case "time-with-cap":
			return timeCap
				? `Enter as minutes:seconds (5:30) or total seconds. Time cap: ${Math.floor(timeCap / 60)}:${String(timeCap % 60).padStart(2, "0")}`
				: "Enter as minutes:seconds (5:30) or total seconds"
		case "rounds-reps":
			return "Enter as rounds+reps (5+12) or rounds.reps (5.12)"
		case "emom":
			return "Enter as minutes:seconds or total seconds"
		default:
			return ""
	}
}

function parseTiebreakValue(
	input: string,
	scheme: string | null,
): number | null {
	if (!input.trim()) return null
	if (scheme === "time") {
		// Parse time input (M:SS or total seconds) to milliseconds
		const timeParts = input.split(":")
		if (timeParts.length === 2) {
			const minutes = Number.parseInt(timeParts[0], 10)
			const seconds = Number.parseInt(timeParts[1], 10)
			if (!Number.isNaN(minutes) && !Number.isNaN(seconds)) {
				return (minutes * 60 + seconds) * 1000
			}
		}
		const totalSeconds = Number.parseInt(input, 10)
		if (!Number.isNaN(totalSeconds)) {
			return totalSeconds * 1000
		}
		return null
	}
	const value = Number.parseInt(input, 10)
	return Number.isNaN(value) ? null : value
}

export function VideoSubmissionForm({
	trackWorkoutId,
	competitionId,
	timezone,
	initialData,
}: VideoSubmissionFormProps) {
	const [videoUrl, setVideoUrl] = useState(
		initialData?.submission?.videoUrl ?? "",
	)
	const [videoValidation, setVideoValidation] =
		useState<VideoUrlValidationState>({
			isValid: false,
			isPending: false,
			error: null,
			parsedUrl: null,
		})
	const [notes, setNotes] = useState(initialData?.submission?.notes ?? "")
	const [isSubmitting, setIsSubmitting] = useState(false)
	const [error, setError] = useState<string | null>(null)
	const [success, setSuccess] = useState<string | null>(null)
	const [hasSubmitted, setHasSubmitted] = useState(!!initialData?.submission)
	// Show preview by default if there's an existing submission
	const [isEditing, setIsEditing] = useState(!initialData?.submission)

	// Local state for submission/score to avoid mutating props
	const [submissionData, setSubmissionData] = useState(
		initialData?.submission ?? null,
	)
	const [scoreData, setScoreData] = useState(
		initialData?.existingScore ?? null,
	)

	// Score form state
	const [scoreInput, setScoreInput] = useState(
		initialData?.existingScore?.displayScore ?? "",
	)
	const [secondaryScore, setSecondaryScore] = useState(
		initialData?.existingScore?.secondaryValue?.toString() ?? "",
	)
	const [tiebreakScore, setTiebreakScore] = useState(() => {
		const tiebreakValue = initialData?.existingScore?.tiebreakValue
		const tiebreakScheme = initialData?.workout?.tiebreakScheme
		if (tiebreakValue === null || tiebreakValue === undefined) return ""
		if (tiebreakScheme === "time") {
			return decodeScore(tiebreakValue, "time", { compact: true })
		}
		return tiebreakValue.toString()
	})
	const [parseResult, setParseResult] = useState<ParseResult | null>(null)

	const submitVideo = useServerFn(submitVideoFn)

	const workout = initialData?.workout

	// Parse score input
	useEffect(() => {
		if (!workout || !scoreInput.trim()) {
			setParseResult(null)
			return
		}

		const result = parseScore(scoreInput, workout.scheme)
		setParseResult(result)
	}, [scoreInput, workout])

	// Derive status from whether time meets or exceeds time cap
	const scoreStatus: "scored" | "cap" = (() => {
		// First check if we can derive from current parse result
		if (
			parseResult?.isValid &&
			parseResult.encoded !== null &&
			workout?.scheme === "time-with-cap" &&
			workout?.timeCap
		) {
			const timeCapMs = workout.timeCap * 1000
			if (parseResult.encoded >= timeCapMs) {
				return "cap"
			}
		}

		// Fall back to existing score's status on initial load (before parseResult is ready)
		if (
			!parseResult &&
			initialData?.existingScore?.status === "cap" &&
			workout?.scheme === "time-with-cap"
		) {
			return "cap"
		}

		return "scored"
	})()

	// If user is not registered, show message
	if (!initialData?.isRegistered) {
		return (
			<Card>
				<CardHeader className="pb-3">
					<CardTitle className="text-lg">Submit Your Result</CardTitle>
				</CardHeader>
				<CardContent>
					<Alert>
						<AlertCircle className="h-4 w-4" />
						<AlertTitle>Registration Required</AlertTitle>
						<AlertDescription>
							You must be registered for this competition to submit your result.
						</AlertDescription>
					</Alert>
				</CardContent>
			</Card>
		)
	}

	// If submission window is not open, show status
	if (!initialData?.canSubmit && initialData?.reason) {
		return (
			<Card>
				<CardHeader className="pb-3">
					<CardTitle className="text-lg">Submit Your Result</CardTitle>
				</CardHeader>
				<CardContent className="space-y-4">
					<Alert variant="destructive">
						<AlertCircle className="h-4 w-4" />
						<AlertTitle>Submission Closed</AlertTitle>
						<AlertDescription>{initialData.reason}</AlertDescription>
					</Alert>
					{initialData?.submissionWindow && (
						<div className="text-sm text-muted-foreground space-y-1">
							<p>
								<strong>Opens:</strong>{" "}
								{formatSubmissionTime(
									initialData.submissionWindow.opensAt,
									timezone,
								)}
							</p>
							<p>
								<strong>Closes:</strong>{" "}
								{formatSubmissionTime(
									initialData.submissionWindow.closesAt,
									timezone,
								)}
							</p>
						</div>
					)}
					{(hasSubmitted || initialData?.existingScore?.displayScore) && (
						<div className="pt-2 border-t space-y-2">
							{initialData?.existingScore?.displayScore && (
								<div>
									<p className="text-sm font-medium">Your claimed score:</p>
									<p className="text-lg font-mono font-bold">
										{initialData.existingScore.displayScore}
										{initialData.existingScore.status === "cap" && " (Capped)"}
									</p>
								</div>
							)}
							{initialData?.submission && (
								<div>
									<p className="text-sm font-medium mb-1">
										Your submitted video:
									</p>
									<a
										href={isSafeUrl(initialData.submission.videoUrl) ? initialData.submission.videoUrl : "#"}
										target="_blank"
										rel="noopener noreferrer"
										className="flex items-center gap-2 text-sm text-primary hover:underline"
									>
										<ExternalLink className="h-4 w-4" />
										{initialData.submission.videoUrl}
									</a>
								</div>
							)}
						</div>
					)}
				</CardContent>
			</Card>
		)
	}

	const handleSubmit = async (e: React.FormEvent) => {
		e.preventDefault()
		setError(null)
		setSuccess(null)

		if (!videoUrl.trim()) {
			setError("Please enter a video URL")
			return
		}

		// Use video URL validation from the component
		if (!videoValidation.isValid) {
			setError(videoValidation.error ?? "Please enter a valid video URL")
			return
		}

		// Validate score if provided and workout exists
		if (scoreInput.trim() && workout) {
			const scoreParseResult = parseScore(scoreInput, workout.scheme)
			if (!scoreParseResult.isValid) {
				setError(
					`Invalid score: ${scoreParseResult.error || "Please check your score entry"}`,
				)
				return
			}
		}

		setIsSubmitting(true)

		try {
			const result = await submitVideo({
				data: {
					trackWorkoutId,
					competitionId,
					videoUrl: videoUrl.trim(),
					notes: notes.trim() || undefined,
					score: scoreInput.trim() || undefined,
					scoreStatus: scoreInput.trim() ? scoreStatus : undefined,
					secondaryScore:
						scoreStatus === "cap"
							? secondaryScore.trim() || undefined
							: undefined,
					tiebreakScore: tiebreakScore.trim() || undefined,
				},
			})

			if (result.success) {
				setSuccess(
					result.isUpdate
						? "Submission updated successfully!"
						: "Submitted successfully!",
				)
				setHasSubmitted(true)
				// Update local state with new submission info and switch to preview
				setSubmissionData({
					id: result.submissionId ?? submissionData?.id ?? "",
					videoUrl: videoUrl.trim(),
					notes: notes.trim() || null,
					submittedAt: submissionData?.submittedAt ?? new Date(),
					updatedAt: new Date(),
				})
				if (scoreInput.trim() && workout) {
					const parsed = parseScore(scoreInput, workout.scheme)
					setScoreData({
						scoreValue: parsed.encoded,
						displayScore: parsed.formatted ?? scoreInput,
						status: scoreStatus,
						secondaryValue: secondaryScore ? Number(secondaryScore) : null,
						tiebreakValue: tiebreakScore
							? parseTiebreakValue(tiebreakScore, workout.tiebreakScheme)
							: null,
					})
				}
				// Switch to preview mode after successful submission
				setTimeout(() => {
					setSuccess(null)
					setIsEditing(false)
				}, 1500)
			}
		} catch (err) {
			setError(err instanceof Error ? err.message : "Failed to submit")
		} finally {
			setIsSubmitting(false)
		}
	}

	const isTimeCapped = workout?.scheme === "time-with-cap"
	const showSecondaryInput = isTimeCapped && scoreStatus === "cap"

	// Show preview when there's a submission and we're not editing
	if (hasSubmitted && submissionData && !isEditing) {
		return (
			<VideoSubmissionPreview
				submission={submissionData}
				score={scoreData}
				workout={
					workout
						? {
								name: workout.name,
								scheme: workout.scheme,
								scoreType: workout.scoreType,
								timeCap: workout.timeCap,
								tiebreakScheme: workout.tiebreakScheme,
							}
						: undefined
				}
				canEdit={initialData.canSubmit}
				editReason={initialData.reason}
				timezone={timezone}
				onEdit={() => setIsEditing(true)}
			/>
		)
	}

	return (
		<Card>
			<CardHeader className="pb-3">
				<div className="flex items-center justify-between">
					<div>
						<CardTitle className="text-lg">
							{hasSubmitted ? "Update Your Result" : "Submit Your Result"}
						</CardTitle>
						<CardDescription>
							{hasSubmitted
								? "Update your submission below"
								: "Submit your score and video for this event"}
						</CardDescription>
					</div>
					{hasSubmitted && (
						<Button
							type="button"
							variant="ghost"
							size="sm"
							onClick={() => setIsEditing(false)}
						>
							Cancel
						</Button>
					)}
				</div>
			</CardHeader>
			<CardContent>
				<form onSubmit={handleSubmit} className="space-y-4">
					{/* Score Section */}
					{workout && (
						<>
							<div className="space-y-2">
								<Label htmlFor="score-input">
									Your {getSchemeLabel(workout.scheme)}
								</Label>
								<Input
									id="score-input"
									value={scoreInput}
									onChange={(e) => setScoreInput(e.target.value)}
									placeholder={getPlaceholder(workout.scheme)}
									className={cn(
										"font-mono",
										parseResult?.error &&
											!parseResult?.isValid &&
											"border-destructive",
									)}
									disabled={isSubmitting}
								/>
								{getHelpText(workout.scheme, workout.timeCap) && (
									<p className="text-xs text-muted-foreground">
										{getHelpText(workout.scheme, workout.timeCap)}
									</p>
								)}
								{parseResult?.isValid && (
									<p className="text-xs text-green-600 dark:text-green-400">
										Parsed as: {parseResult.formatted}
										{scoreStatus === "cap" && " (Time Cap)"}
									</p>
								)}
								{parseResult?.error && (
									<p className="text-xs text-destructive">
										{parseResult.error}
									</p>
								)}
							</div>

							{/* Secondary Score (reps at cap) - shown when time equals time cap */}
							{scoreStatus === "cap" && (
								<p className="text-xs text-amber-600 dark:text-amber-400">
									You hit the time cap. Enter the reps you completed below.
								</p>
							)}
							{showSecondaryInput && (
								<div className="space-y-2">
									<Label htmlFor="secondary-input">Reps Completed at Cap</Label>
									<Input
										id="secondary-input"
										type="number"
										value={secondaryScore}
										onChange={(e) => setSecondaryScore(e.target.value)}
										placeholder="e.g., 150"
										min="0"
										disabled={isSubmitting}
									/>
									<p className="text-xs text-muted-foreground">
										Total reps/work completed when the time cap hit
									</p>
								</div>
							)}

							{/* Tiebreak Score */}
							{workout.tiebreakScheme && (
								<div className="space-y-2">
									<Label htmlFor="tiebreak-input">
										Tiebreak (
										{workout.tiebreakScheme === "time" ? "Time" : "Reps"})
									</Label>
									<Input
										id="tiebreak-input"
										value={tiebreakScore}
										onChange={(e) => setTiebreakScore(e.target.value)}
										placeholder={
											workout.tiebreakScheme === "time"
												? "e.g., 3:45"
												: "e.g., 100"
										}
										className="font-mono"
										disabled={isSubmitting}
									/>
									<p className="text-xs text-muted-foreground">
										{workout.tiebreakScheme === "time"
											? "Time to complete specified reps/work"
											: "Reps completed for tiebreak"}
									</p>
								</div>
							)}

							<Separator />
						</>
					)}

					{/* Video URL Input */}
					<div className="space-y-2">
						<Label htmlFor="videoUrl">Video URL</Label>
						<VideoUrlInput
							id="videoUrl"
							value={videoUrl}
							onChange={setVideoUrl}
							onValidationChange={setVideoValidation}
							required
							disabled={isSubmitting}
							showPlatformBadge
							showPreviewLink
						/>
						<p className="text-xs text-muted-foreground">
							Upload your video to {getSupportedPlatformsText()} (unlisted is
							fine) and paste the link
						</p>
					</div>

					{/* Notes Input */}
					<div className="space-y-2">
						<Label htmlFor="notes">Notes (Optional)</Label>
						<Textarea
							id="notes"
							placeholder="Any additional information about your submission..."
							value={notes}
							onChange={(e) => setNotes(e.target.value)}
							rows={2}
							disabled={isSubmitting}
							maxLength={1000}
						/>
					</div>

					{/* Error Message */}
					{error && (
						<Alert variant="destructive">
							<AlertCircle className="h-4 w-4" />
							<AlertDescription>{error}</AlertDescription>
						</Alert>
					)}

					{/* Success Message */}
					{success && (
						<Alert className="border-green-500 text-green-700 dark:text-green-400">
							<CheckCircle2 className="h-4 w-4" />
							<AlertDescription>{success}</AlertDescription>
						</Alert>
					)}

					{/* Submit Button */}
					<Button type="submit" className="w-full" disabled={isSubmitting}>
						{isSubmitting ? (
							<>
								<Loader2 className="mr-2 h-4 w-4 animate-spin" />
								Submitting...
							</>
						) : hasSubmitted ? (
							"Update Submission"
						) : (
							"Submit Result"
						)}
					</Button>

					{/* Previous Submission Info */}
					{hasSubmitted && initialData?.submission && (
						<div className="pt-2 border-t text-xs text-muted-foreground">
							Last submitted:{" "}
							{formatSubmissionTime(
								initialData.submission.submittedAt,
								timezone,
							)}
						</div>
					)}
				</form>
			</CardContent>
		</Card>
	)
}

"use client"

import { AlertCircle, ExternalLink, Youtube } from "lucide-react"
import { useMemo } from "react"
import { Alert, AlertDescription } from "@/components/ui/alert"
import { cn } from "@/lib/utils"

interface YouTubeEmbedProps {
	url: string
	className?: string
	title?: string
}

function isSafeUrl(url: string): boolean {
	try {
		const parsed = new URL(url)
		return parsed.protocol === "http:" || parsed.protocol === "https:"
	} catch {
		return false
	}
}

/**
 * Extracts YouTube video ID from various YouTube URL formats
 * Supports: youtube.com/watch?v=, youtu.be/, youtube.com/embed/, youtube.com/shorts/
 */
function extractYouTubeVideoId(url: string): string | null {
	if (!url) return null

	try {
		const urlObj = new URL(url)
		const hostname = urlObj.hostname.toLowerCase()

		// Standard youtube.com URLs
		if (hostname.includes("youtube.com")) {
			// /watch?v= format
			const videoId = urlObj.searchParams.get("v")
			if (videoId) return videoId

			// /embed/ format
			const embedMatch = urlObj.pathname.match(/\/embed\/([^/?]+)/)
			if (embedMatch) return embedMatch[1]

			// /shorts/ format
			const shortsMatch = urlObj.pathname.match(/\/shorts\/([^/?]+)/)
			if (shortsMatch) return shortsMatch[1]
		}

		// Short youtu.be URLs
		if (hostname.includes("youtu.be")) {
			const id = urlObj.pathname.slice(1).split(/[?&]/)[0]
			if (id) return id
		}
	} catch {
		// Invalid URL, try regex fallback
		const regexPatterns = [
			/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/|youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,
		]

		for (const pattern of regexPatterns) {
			const match = url.match(pattern)
			if (match) return match[1]
		}
	}

	return null
}

/**
 * Checks if a URL is a valid YouTube URL
 */
export function isYouTubeUrl(url: string): boolean {
	return extractYouTubeVideoId(url) !== null
}

export function YouTubeEmbed({ url, className, title }: YouTubeEmbedProps) {
	const videoId = useMemo(() => extractYouTubeVideoId(url), [url])

	if (!videoId) {
		// Not a YouTube URL - show a link instead
		return (
			<div
				className={cn(
					"relative aspect-video w-full overflow-hidden rounded-lg bg-muted",
					className,
				)}
			>
				<div className="absolute inset-0 flex flex-col items-center justify-center gap-3 p-4 text-center">
					<Alert variant="default" className="max-w-sm">
						<AlertCircle className="h-4 w-4" />
						<AlertDescription className="text-left">
							<p className="font-medium mb-2">Video preview unavailable</p>
							<p className="text-xs text-muted-foreground mb-3">
								Only YouTube videos can be previewed inline
							</p>
							<a
								href={isSafeUrl(url) ? url : "#"}
								target="_blank"
								rel="noopener noreferrer"
								className="inline-flex items-center gap-2 text-primary hover:underline text-sm"
							>
								<ExternalLink className="h-4 w-4" />
								Open video in new tab
							</a>
						</AlertDescription>
					</Alert>
				</div>
			</div>
		)
	}

	return (
		<div
			className={cn(
				"relative aspect-video w-full overflow-hidden rounded-lg bg-black",
				className,
			)}
		>
			<iframe
				src={`https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1`}
				title={title || "YouTube video player"}
				allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
				allowFullScreen
				className="absolute inset-0 h-full w-full"
				loading="lazy"
			/>
		</div>
	)
}

export function YouTubeThumbnail({
	url,
	className,
}: {
	url: string
	className?: string
}) {
	const videoId = useMemo(() => extractYouTubeVideoId(url), [url])

	if (!videoId) {
		return (
			<div
				className={cn(
					"relative aspect-video w-full overflow-hidden rounded-lg bg-muted flex items-center justify-center",
					className,
				)}
			>
				<Youtube className="h-8 w-8 text-muted-foreground" />
			</div>
		)
	}

	return (
		<div
			className={cn(
				"relative aspect-video w-full overflow-hidden rounded-lg",
				className,
			)}
		>
			<img
				src={`https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`}
				alt="Video thumbnail"
				className="absolute inset-0 h-full w-full object-cover"
				loading="lazy"
				onError={(e) => {
					// Fallback to medium quality if maxres doesn't exist
					;(e.target as HTMLImageElement).src =
						`https://img.youtube.com/vi/${videoId}/mqdefault.jpg`
				}}
			/>
			<div className="absolute inset-0 flex items-center justify-center">
				<div className="rounded-full bg-red-600 p-3 shadow-lg">
					<Youtube className="h-6 w-6 text-white" />
				</div>
			</div>
		</div>
	)
}

"use client"

import {
	Calendar,
	CheckCircle2,
	Clock,
	Edit3,
	ExternalLink,
	FileText,
	Trophy,
} from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
	Card,
	CardContent,
	CardDescription,
	CardHeader,
	CardTitle,
} from "@/components/ui/card"
import { Separator } from "@/components/ui/separator"
import type { ScoreType, WorkoutScheme } from "@/lib/scoring"
import { YouTubeEmbed, isYouTubeUrl } from "./youtube-embed"

interface VideoSubmissionPreviewProps {
	submission: {
		id: string
		videoUrl: string
		notes: string | null
		submittedAt: Date
		updatedAt: Date
	}
	score?: {
		scoreValue: number | null
		displayScore: string | null
		status: string | null
		secondaryValue: number | null
		tiebreakValue: number | null
	} | null
	workout?: {
		name: string
		scheme: WorkoutScheme
		scoreType: ScoreType | null
		timeCap: number | null
		tiebreakScheme: string | null
	} | null
	canEdit: boolean
	editReason?: string
	timezone?: string | null
	onEdit?: () => void
}

function formatSubmissionTime(
	date: Date | string,
	timezone?: string | null,
): string {
	const d = typeof date === "string" ? new Date(date) : date
	return new Intl.DateTimeFormat("en-US", {
		weekday: "short",
		month: "short",
		day: "numeric",
		hour: "numeric",
		minute: "2-digit",
		timeZone: timezone ?? undefined,
	}).format(d)
}

function isSafeUrl(url: string): boolean {
	try {
		const parsed = new URL(url)
		return parsed.protocol === "http:" || parsed.protocol === "https:"
	} catch {
		return false
	}
}

function formatTiebreakTime(milliseconds: number): string {
	const totalSeconds = Math.floor(milliseconds / 1000)
	const minutes = Math.floor(totalSeconds / 60)
	const seconds = totalSeconds % 60
	return `${minutes}:${seconds.toString().padStart(2, "0")}`
}

function getSchemeLabel(scheme: WorkoutScheme): string {
	switch (scheme) {
		case "time":
		case "time-with-cap":
			return "Time"
		case "rounds-reps":
			return "Rounds + Reps"
		case "reps":
			return "Reps"
		case "load":
			return "Load"
		case "calories":
			return "Calories"
		case "meters":
			return "Meters"
		case "feet":
			return "Feet"
		case "points":
			return "Points"
		case "emom":
			return "Time"
		case "pass-fail":
			return "Rounds Passed"
		default:
			return "Score"
	}
}

export function VideoSubmissionPreview({
	submission,
	score,
	workout,
	canEdit,
	editReason,
	timezone,
	onEdit,
}: VideoSubmissionPreviewProps) {
	const isYouTube = isYouTubeUrl(submission.videoUrl)
	const hasUpdated =
		submission.updatedAt.getTime() !== submission.submittedAt.getTime()

	return (
		<Card className="overflow-hidden">
			<CardHeader className="pb-3">
				<div className="flex items-center justify-between gap-4">
					<div className="flex items-center gap-2">
						<CheckCircle2 className="h-5 w-5 text-green-600 dark:text-green-400" />
						<CardTitle className="text-lg">Submission Complete</CardTitle>
					</div>
					{canEdit && onEdit && (
						<Button
							variant="outline"
							size="sm"
							className="gap-1.5 h-auto py-1 px-2 text-xs"
							onClick={onEdit}
						>
							<Edit3 className="h-3 w-3" />
							Edit
						</Button>
					)}
				</div>
				<CardDescription>
					{canEdit
						? "Your submission is recorded. You can still update it while the submission window is open."
						: editReason || "Submission window is closed."}
				</CardDescription>
			</CardHeader>

			<CardContent className="space-y-4">
				{/* Video Preview */}
				<div className="space-y-2">
					{isYouTube ? (
						<YouTubeEmbed
							url={submission.videoUrl}
							title={workout?.name || "Workout submission"}
						/>
					) : (
						<div className="rounded-lg border bg-muted/50 p-4">
							<div className="flex items-center gap-3">
								<FileText className="h-5 w-5 text-muted-foreground" />
								<div className="flex-1 min-w-0">
									<p className="text-sm font-medium truncate">
										{submission.videoUrl}
									</p>
									<p className="text-xs text-muted-foreground">
										External video link
									</p>
								</div>
								<a
									href={isSafeUrl(submission.videoUrl) ? submission.videoUrl : "#"}
									target="_blank"
									rel="noopener noreferrer"
									className="flex items-center gap-1.5 text-sm text-primary hover:underline shrink-0"
								>
									<ExternalLink className="h-4 w-4" />
									Open
								</a>
							</div>
						</div>
					)}
				</div>

				<Separator />

				{/* Score Display */}
				{score?.displayScore && (
					<div className="flex items-start gap-3 rounded-lg bg-muted/50 p-4">
						<Trophy className="h-5 w-5 text-amber-500 mt-0.5" />
						<div className="flex-1">
							<p className="text-xs text-muted-foreground uppercase tracking-wider mb-1">
								{workout
									? `Your ${getSchemeLabel(workout.scheme)}`
									: "Your Score"}
							</p>
							<p className="text-2xl font-mono font-bold">
								{score.displayScore}
								{score.status === "cap" && (
									<Badge variant="secondary" className="ml-2 text-xs">
										Capped
									</Badge>
								)}
							</p>
							{score.secondaryValue !== null && score.status === "cap" && (
								<p className="text-sm text-muted-foreground mt-1">
									{score.secondaryValue} reps completed at cap
								</p>
							)}
							{score.tiebreakValue !== null && workout?.tiebreakScheme && (
								<p className="text-sm text-muted-foreground mt-1">
									Tiebreak:{" "}
									{workout.tiebreakScheme === "time"
										? formatTiebreakTime(score.tiebreakValue)
										: score.tiebreakValue}
								</p>
							)}
						</div>
					</div>
				)}

				{/* Notes */}
				{submission.notes && (
					<div className="rounded-lg bg-muted/50 p-4">
						<p className="text-xs text-muted-foreground uppercase tracking-wider mb-2">
							Notes
						</p>
						<p className="text-sm whitespace-pre-wrap">{submission.notes}</p>
					</div>
				)}

				{/* Submission Metadata */}
				<div className="flex flex-wrap items-center gap-x-4 gap-y-2 text-xs text-muted-foreground">
					<div className="flex items-center gap-1.5">
						<Calendar className="h-3.5 w-3.5" />
						<span>
							Submitted {formatSubmissionTime(submission.submittedAt, timezone)}
						</span>
					</div>
					{hasUpdated && (
						<div className="flex items-center gap-1.5">
							<Clock className="h-3.5 w-3.5" />
							<span>
								Updated {formatSubmissionTime(submission.updatedAt, timezone)}
							</span>
						</div>
					)}
				</div>

				{/* Edit Status Banner */}
				{canEdit && (
					<div className="rounded-lg border border-green-500/30 bg-green-500/10 px-4 py-3">
						<div className="flex items-center gap-2">
							<Edit3 className="h-4 w-4 text-green-600 dark:text-green-400" />
							<p className="text-sm text-green-700 dark:text-green-300">
								Submission window is open - you can still update your submission
							</p>
						</div>
					</div>
				)}

				{!canEdit && editReason && (
					<div className="rounded-lg border border-amber-500/30 bg-amber-500/10 px-4 py-3">
						<div className="flex items-center gap-2">
							<Clock className="h-4 w-4 text-amber-600 dark:text-amber-400" />
							<p className="text-sm text-amber-700 dark:text-amber-300">
								{editReason}
							</p>
						</div>
					</div>
				)}
			</CardContent>
		</Card>
	)
}

